noncompliant:
try // Noncompliant - identical catch blocks should be merged
{
    DoFirstThing();
}
catch (IOException e)
{
    Log(e);
}

try
{
    DoSecondThing();
}
catch (IOException e)
{
    Log(e);
}

compliant:
try // Compliant - merged into single try block
{
    DoFirstThing();
    DoSecondThing();
}
catch (IOException e)
{
    Log(e);
}
